#include<iostream>
using namespace std;
long long m,s,t,i,f[700000];
int main() {
	cin>>m>>s>>t;
	for(i=1; i<=t; i++) {
		if(m>=10) {
			f[i]=f[i-1]+60;
			m-=10;
		} else {
			f[i]=f[i-1];
			m+=4;
		}
	}
	for(i=1; i<=t; i++) {
		if(f[i]<f[i-1]+17)f[i]=f[i-1]+17;
		if(f[i]>=s) {
			cout<<"Yes"<<endl;
			cout<<i<<endl;
			return 0;
		}
	}
	cout<<"No"<<"\n"<<f[t];
	return 0;
}
